#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, n, sizeof(int), compare);
        int classes = 1;
        int last = arr[0];
        for (int i = 1; i < n; i++) {
            if (arr[i] - last > k) {
                classes++;
                last = arr[i];
            }
        }
        printf("%d\n", classes);
    }
    return 0;
}

